using System.Net;using System.Net.Http.Json;using DBH.UnitTest.Shared;namespace DBH.UnitTest.ApiTests;/// <summary>/// Bad case: Try to grant consent with invalid/missing fields/// Expected: 400 Bad Request/// </summary>public class ConsentServiceTests_GrantConsent_WithInvalidData_ShouldReturnBadRequest : ApiTestBase{    protected override IReadOnlyCollection<string> RequiredServices => new[]    {        "AuthService",        "ConsentService"    };    [SkippableFact]    public async Task GrantConsent_WithMissingGranteeDid_ShouldReturnBadRequest()    {        await AuthenticateAsPatientAsync(ConsentClient);        var request = new         {             patientDid = TestSeedData.PatientUserId.ToString(),             scope = "read"         };        var response = await PostAsJsonWithRetryAsync(ConsentClient, ApiEndpoints.Consents.Grant, request);        Assert.True(            response.StatusCode == HttpStatusCode.BadRequest ||             response.StatusCode == HttpStatusCode.UnprocessableEntity,            $"Expected 400 or 422, got {response.StatusCode}");    }    [SkippableFact]    public async Task GrantConsent_WithMissingPatientDid_ShouldReturnBadRequest()    {        await AuthenticateAsPatientAsync(ConsentClient);        var request = new         {             granteeDid = TestSeedData.DoctorUserId.ToString(),             scope = "read"         };        var response = await PostAsJsonWithRetryAsync(ConsentClient, ApiEndpoints.Consents.Grant, request);        Assert.True(            response.StatusCode == HttpStatusCode.BadRequest ||             response.StatusCode == HttpStatusCode.UnprocessableEntity,            $"Expected 400 or 422, got {response.StatusCode}");    }}
